```class Solution {
public:
    bool checkSubarraySum(vector<int>& nums, int k) {
        int n = nums.size(), prefix = 0, cnt[10005] = {};
        cnt[0] = 1;
        for (int i = 0; i < n; i++) {
            prefix = (prefix + nums[i]) % k;
            if (cnt[prefix]) return true;
            cnt[prefix]++;
        }
        for (int i = 1; i < n; i++) {
            prefix = (prefix + nums[i - 1]) % k;
            if (cnt[prefix]) return true;
            cnt[prefix]++;
        }
        return false;
    }
};
